}

package com.example.Cmms.domain.equipamento;

import jakarta.validation.constraints.NotBlank;
import jakarta.validation.constraints.NotNull;

public record DadosCadastroEquipamento(
        @NotBlank
        String nome,

        @NotBlank
        String codigo,

        @NotNull
        Status status
) {
}

package controller;

import domain.equipamento.DadosCadastroEquipamento;
import domain.equipamento.DadosDetalhamentoEquipamento;
import domain.equipamento.Equipamento;
import domain.equipamento.EquipamentoRepository;
import jakarta.validation.Valid;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.ResponseEntity;
import org.springframework.transaction.annotation.Transactional;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.util.UriComponentsBuilder;


@RestController
@RequestMapping("equipamento")
public class EquipamentoController {

    @Autowired
    private EquipamentoRepository repository;

    @PostMapping
    @Transactional
    public ResponseEntity cadastrarEquipamento(@RequestBody @Valid DadosCadastroEquipamento dados, UriComponentsBuilder uriBuilder) {
        var equipamento = new Equipamento(null, dados.nome(), dados.codigo(), dados.status(), null);
        repository.save(equipamento);

        var uri = uriBuilder.path("/equipamentos/{id}").buildAndExpand(equipamento.getId()).toUri();
        var dto = new DadosDetalhamentoEquipamento(equipamento);
        return ResponseEntity.created(uri).body(dto);
    }


}

